const DEFAULT_SLIDE = {
	id: '',
	image: null,
	focalPoint: { x: 0.5, y: 0.5 },
	duotone: null,
	caption: '',
	mobileImage: null,
	mobileCaption: '',
	mobileDuotone: null,
};

const generateSlideId = () => {
	return 'slide-' + Math.random().toString(36).substr(2, 9);
};

/**
 * Generate duotone SVG filter markup
 */
const parseColor = (hex) => {
	let color = hex.replace('#', '');
	if (color.length === 3) {
		color = color[0] + color[0] + color[1] + color[1] + color[2] + color[2];
	}
	return {
		r: parseInt(color.slice(0, 2), 16) / 255,
		g: parseInt(color.slice(2, 4), 16) / 255,
		b: parseInt(color.slice(4, 6), 16) / 255,
	};
};

const getDuotoneFilterPrimitives = (duotone, filterId) => {
	const shadow = parseColor(duotone[0]);
	const highlight = parseColor(duotone[1]);

	return (
		<filter id={filterId}>
			<feColorMatrix
				colorInterpolationFilters="sRGB"
				type="matrix"
				values=".299 .587 .114 0 0 .299 .587 .114 0 0 .299 .587 .114 0 0 0 0 0 1 0"
			/>
			<feComponentTransfer colorInterpolationFilters="sRGB">
				<feFuncR type="table" tableValues={`${shadow.r} ${highlight.r}`} />
				<feFuncG type="table" tableValues={`${shadow.g} ${highlight.g}`} />
				<feFuncB type="table" tableValues={`${shadow.b} ${highlight.b}`} />
				<feFuncA type="table" tableValues="0 1" />
			</feComponentTransfer>
		</filter>
	);
};

const getDuotoneFilter = (duotone, filterId) => {
	if (!Array.isArray(duotone) || duotone.length < 2) {
		return null;
	}

	return (
		<svg
			xmlns="http://www.w3.org/2000/svg"
			viewBox="0 0 0 0"
			width="0"
			height="0"
			focusable="false"
			role="none"
			style={{ visibility: 'hidden', position: 'absolute', left: '-9999px', overflow: 'hidden' }}
			aria-hidden="true"
		>
			<defs>
				{getDuotoneFilterPrimitives(duotone, filterId)}
			</defs>
		</svg>
	);
};

/**
 * Render an image with duotone filter applied inline via SVG <image>.
 * This avoids url(#id) resolution issues in WordPress's iframed block editor
 * where a <base> tag can break fragment-only filter references.
 */
const getDuotoneImage = (duotone, filterId, imageUrl, imageAlt) => {
	if (!Array.isArray(duotone) || duotone.length < 2) {
		return null;
	}

	return (
		<svg
			xmlns="http://www.w3.org/2000/svg"
			style={{ width: '100%', height: '100%' }}
			role="img"
			aria-label={imageAlt || ''}
		>
			<defs>
				{getDuotoneFilterPrimitives(duotone, filterId)}
			</defs>
			<image
				href={imageUrl}
				x="0"
				y="0"
				width="100%"
				height="100%"
				preserveAspectRatio="xMidYMid slice"
				filter={`url(#${filterId})`}
			/>
		</svg>
	);
};

/**
 * Convert spacing preset value to CSS custom property
 * Converts "var:preset|spacing|50" to "var(--wp--preset--spacing--50)"
 */
const getSpacingPresetCssVar = (value) => {
	if (!value) return undefined;

	// Check if it's a preset value
	if (typeof value === 'string' && value.startsWith('var:preset|')) {
		const parts = value.split('|');
		if (parts.length === 3) {
			const [, type, slug] = parts;
			return `var(--wp--preset--${type}--${slug})`;
		}
	}

	// Return as-is if it's a regular CSS value
	return value;
};

const Edit = ({ attributes, setAttributes, clientId }) => {
	const { slides, contentPosition, imageDisplayMode, contentBackgroundColor, contentTextColor, imagesBackgroundColor, captionTextColor, contentPadding, featherEdge } = attributes;
	const [showSlideManager, setShowSlideManager] = useState(false);

	// Get theme colors from theme.json
	const themeColors = useSetting('color.palette');

	// Auto-add first slide when block is inserted
	useEffect(() => {
		if (slides.length === 0) {
			setAttributes({
				slides: [{ ...DEFAULT_SLIDE, id: generateSlideId() }],
			});
		}
	}, []);

	// Apply duotone filter using the iframe document's actual URL to avoid
	// the <base> tag breaking fragment-only url(#id) CSS filter references.
	const duotoneImgRef = useRef();
	useEffect(() => {
		const el = duotoneImgRef.current;
		if (!el) return;

		const firstSlide = slides[0];
		if (Array.isArray(firstSlide?.duotone) && firstSlide.duotone.length >= 2) {
			const docUrl = el.ownerDocument.URL.split('#')[0];
			el.style.filter = `url('${docUrl}#editor-duotone-${clientId}')`;
		} else {
			el.style.filter = '';
		}
	}, [slides, clientId]);

	const addSlide = () => {
		const newSlide = {
			...DEFAULT_SLIDE,
			id: generateSlideId(),
		};
		setAttributes({ slides: [...slides, newSlide] });
	};

	const removeSlide = (slideIndex) => {
		if (slides.length === 1) {
			return;
		}
		const newSlides = [...slides];
		newSlides.splice(slideIndex, 1);
		setAttributes({ slides: newSlides });
	};

	const updateSlide = (slideIndex, updates) => {
		const newSlides = [...slides];
		newSlides[slideIndex] = { ...newSlides[slideIndex], ...updates };
		setAttributes({ slides: newSlides });
	};

	const moveSlideUp = (slideIndex) => {
		if (slideIndex === 0) return;
		const newSlides = [...slides];
		[newSlides[slideIndex - 1], newSlides[slideIndex]] = [
			newSlides[slideIndex],
			newSlides[slideIndex - 1],
		];
		setAttributes({ slides: newSlides });
	};

	const moveSlideDown = (slideIndex) => {
		if (slideIndex === slides.length - 1) return;
		const newSlides = [...slides];
		[newSlides[slideIndex], newSlides[slideIndex + 1]] = [
			newSlides[slideIndex + 1],
			newSlides[slideIndex],
		];
		setAttributes({ slides: newSlides });
	};

	const duplicateSlide = (slideIndex) => {
		const slideToDuplicate = slides[slideIndex];
		const duplicatedSlide = {
			...JSON.parse(JSON.stringify(slideToDuplicate)),
			id: generateSlideId(),
		};
		const newSlides = [...slides];
		newSlides.splice(slideIndex + 1, 0, duplicatedSlide);
		setAttributes({ slides: newSlides });
	};

	const onSelectImage = (slideIndex, media) => {
		const imageData = {
			id: media.id,
			url: media.url,
			alt: media.alt || '',
			caption: media.caption || '',
			sizes: media.sizes || {},
			width: media.width || null,
			height: media.height || null,
		};

		// Pre-fill slide caption with image caption from media library
		// Only set if the slide doesn't already have a custom caption
		const currentSlide = slides[slideIndex];
		const updates = { image: imageData };

		// If this is a new image or the slide has no custom caption, use the media caption
		if (!currentSlide.caption || currentSlide.image?.id !== media.id) {
			updates.caption = media.caption || '';
		}

		updateSlide(slideIndex, updates);
	};

	const onRemoveImage = (slideIndex) => {
		updateSlide(slideIndex, { image: null });
	};

	const isFeatherActive = featherEdge && imageDisplayMode === 'cover' && !!contentBackgroundColor;

	const blockProps = useBlockProps({
		className: `caes-motion-scroll-editor content-${contentPosition} image-mode-${imageDisplayMode}${isFeatherActive ? ' has-feather-edge' : ''}`,
		style: isFeatherActive ? { backgroundColor: contentBackgroundColor } : {},
	});

	return (
		<>
			<BlockControls>
				<ToolbarGroup>
					<ToolbarButton
						icon="align-pull-left"
						label={__('Show content on right', 'caes-motion-scroll')}
						isActive={contentPosition === 'right'}
						onClick={() => setAttributes({ contentPosition: 'right' })}
					/>
					<ToolbarButton
						icon="align-pull-right"
						label={__('Show content on left', 'caes-motion-scroll')}
						isActive={contentPosition === 'left'}
						onClick={() => setAttributes({ contentPosition: 'left' })}
					/>
				</ToolbarGroup>
				<ToolbarGroup>
					<ToolbarButton
						icon="admin-generic"
						label={__('Manage Images', 'caes-motion-scroll')}
						onClick={() => setShowSlideManager(true)}
					/>
				</ToolbarGroup>
			</BlockControls>

			<InspectorControls>
				<PanelBody title={__('Images', 'caes-motion-scroll')} initialOpen={true}>
					<p style={{ marginBottom: '12px', color: '#757575', fontSize: '13px' }}>
						{__('This block has', 'caes-motion-scroll')} {slides.length} {slides.length === 1 ? __('image', 'caes-motion-scroll') : __('images', 'caes-motion-scroll')}.
					</p>
					<Button
						variant="secondary"
						onClick={() => setShowSlideManager(true)}
						style={{ width: '100%' }}
					>
						{__('Manage Images', 'caes-motion-scroll')}
					</Button>
				</PanelBody>
				<PanelBody title={__('Display Settings', 'caes-motion-scroll')} initialOpen={false}>
					<SelectControl
						label={__('Image Display Mode', 'caes-motion-scroll')}
						value={imageDisplayMode}
						options={[
							{ label: __('Fill background (cover)', 'caes-motion-scroll'), value: 'cover' },
							{ label: __('Fit to width (contain)', 'caes-motion-scroll'), value: 'contain' },
						]}
						onChange={(value) => setAttributes({ imageDisplayMode: value })}
						help={__('Choose how images are displayed in the sticky column.', 'caes-motion-scroll')}
					/>
					{imageDisplayMode === 'cover' && (
						<ToggleControl
							label={__('Feather Edge', 'caes-motion-scroll')}
							help={__('Softly blend the image column into the content background at the shared edge.', 'caes-motion-scroll')}
							checked={!!featherEdge}
							onChange={(value) => setAttributes({ featherEdge: value })}
						/>
					)}
				</PanelBody>
				<PanelBody title={__('Content Area', 'caes-motion-scroll')} initialOpen={false}>
					<SpacingSizesControl
						label={__('Padding', 'caes-motion-scroll')}
						values={contentPadding}
						onChange={(value) => setAttributes({ contentPadding: value })}
						sides={['top', 'right', 'bottom', 'left']}
					/>
					<div style={{ marginBottom: '16px', marginTop: '16px' }}>
						<div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' }}>
							<label style={{ fontWeight: 500, fontSize: '13px', margin: 0 }}>
								{__('Background Color', 'caes-motion-scroll')}
							</label>
							{contentBackgroundColor && (
								<Button
									size="small"
									variant="tertiary"
									onClick={() => setAttributes({ contentBackgroundColor: '' })}
								>
									{__('Clear', 'caes-motion-scroll')}
								</Button>
							)}
						</div>
						<Dropdown
							popoverProps={{ placement: 'left-start' }}
							renderToggle={({ isOpen, onToggle }) => (
								<Button
									onClick={onToggle}
									aria-expanded={isOpen}
									className="block-editor-panel-color-gradient-settings__dropdown"
								>
									<HStack justify="flex-start">
										<ZStack isLayered={false}>
											<Flex>
												<ColorIndicator colorValue={contentBackgroundColor || 'transparent'} />
											</Flex>
										</ZStack>
										<FlexItem className="block-editor-panel-color-gradient-settings__color-name">
											{contentBackgroundColor ? contentBackgroundColor : __('Default', 'caes-motion-scroll')}
										</FlexItem>
									</HStack>
								</Button>
							)}
							renderContent={() => (
								<ColorPalette
									value={contentBackgroundColor}
									onChange={(value) => setAttributes({ contentBackgroundColor: value })}
									colors={themeColors}
									enableAlpha
								/>
							)}
						/>
					</div>
					<div style={{ marginBottom: '16px' }}>
						<div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' }}>
							<label style={{ fontWeight: 500, fontSize: '13px', margin: 0 }}>
								{__('Text Color', 'caes-motion-scroll')}
							</label>
							{contentTextColor && (
								<Button
									size="small"
									variant="tertiary"
									onClick={() => setAttributes({ contentTextColor: '' })}
								>
									{__('Clear', 'caes-motion-scroll')}
								</Button>
							)}
						</div>
						<Dropdown
							popoverProps={{ placement: 'left-start' }}
							renderToggle={({ isOpen, onToggle }) => (
								<Button
									onClick={onToggle}
									aria-expanded={isOpen}
									className="block-editor-panel-color-gradient-settings__dropdown"
								>
									<HStack justify="flex-start">
										<ZStack isLayered={false}>
											<Flex>
												<ColorIndicator colorValue={contentTextColor || 'inherit'} />
											</Flex>
										</ZStack>
										<FlexItem className="block-editor-panel-color-gradient-settings__color-name">
											{contentTextColor ? contentTextColor : __('Default', 'caes-motion-scroll')}
										</FlexItem>
									</HStack>
								</Button>
							)}
							renderContent={() => (
								<ColorPalette
									value={contentTextColor}
									onChange={(value) => setAttributes({ contentTextColor: value })}
									colors={themeColors}
									enableAlpha
								/>
							)}
						/>
					</div>
				</PanelBody>
				<PanelBody title={__('Images Area', 'caes-motion-scroll')} initialOpen={false}>
					<div style={{ marginBottom: '16px' }}>
						<div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' }}>
							<label style={{ fontWeight: 500, fontSize: '13px', margin: 0 }}>
								{__('Background Color', 'caes-motion-scroll')}
							</label>
							{imagesBackgroundColor && imagesBackgroundColor !== '#000000' && (
								<Button
									size="small"
									variant="tertiary"
									onClick={() => setAttributes({ imagesBackgroundColor: '#000000' })}
								>
									{__('Reset', 'caes-motion-scroll')}
								</Button>
							)}
						</div>
						<Dropdown
							popoverProps={{ placement: 'left-start' }}
							renderToggle={({ isOpen, onToggle }) => (
								<Button
									onClick={onToggle}
									aria-expanded={isOpen}
									className="block-editor-panel-color-gradient-settings__dropdown"
								>
									<HStack justify="flex-start">
										<ZStack isLayered={false}>
											<Flex>
												<ColorIndicator colorValue={imagesBackgroundColor || '#000000'} />
											</Flex>
										</ZStack>
										<FlexItem className="block-editor-panel-color-gradient-settings__color-name">
											{imagesBackgroundColor || '#000000'}
										</FlexItem>
									</HStack>
								</Button>
							)}
							renderContent={() => (
								<ColorPalette
									value={imagesBackgroundColor}
									onChange={(value) => setAttributes({ imagesBackgroundColor: value })}
									colors={themeColors}
									enableAlpha
								/>
							)}
						/>
					</div>
					<div style={{ marginBottom: '16px' }}>
						<div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' }}>
							<label style={{ fontWeight: 500, fontSize: '13px', margin: 0 }}>
								{__('Caption Text Color', 'caes-motion-scroll')}
							</label>
							{captionTextColor && captionTextColor !== '#ffffff' && (
								<Button
									size="small"
									variant="tertiary"
									onClick={() => setAttributes({ captionTextColor: '#ffffff' })}
								>
									{__('Reset', 'caes-motion-scroll')}
								</Button>
							)}
						</div>
						<Dropdown
							popoverProps={{ placement: 'left-start' }}
							renderToggle={({ isOpen, onToggle }) => (
								<Button
									onClick={onToggle}
									aria-expanded={isOpen}
									className="block-editor-panel-color-gradient-settings__dropdown"
								>
									<HStack justify="flex-start">
										<ZStack isLayered={false}>
											<Flex>
												<ColorIndicator colorValue={captionTextColor || '#ffffff'} />
											</Flex>
										</ZStack>
										<FlexItem className="block-editor-panel-color-gradient-settings__color-name">
											{captionTextColor || '#ffffff'}
										</FlexItem>
									</HStack>
								</Button>
							)}
							renderContent={() => (
								<ColorPalette
									value={captionTextColor}
									onChange={(value) => setAttributes({ captionTextColor: value })}
									colors={themeColors}
									enableAlpha
								/>
							)}
						/>
					</div>
				</PanelBody>
			</InspectorControls>

			<div {...blockProps}>
				<div className="motion-scroll-editor-layout">
					<div className="motion-scroll-editor-images" style={{ backgroundColor: isFeatherActive ? contentBackgroundColor : (imagesBackgroundColor || '#000') }}>
						<div className="motion-scroll-images-preview">
							{slides.length > 0 && slides[0]?.duotone && getDuotoneFilter(slides[0].duotone, `editor-duotone-${clientId}`)}
							{slides.length > 0 && slides[0]?.image ? (
								<>
									<img
										ref={duotoneImgRef}
										src={slides[0].image.url}
										alt={slides[0].image.alt || ''}
									/>
									{slides[0].caption && (
										<figcaption
											className="motion-scroll-caption-preview"
											style={{ color: captionTextColor || '#ffffff' }}
										>
											{slides[0].caption}
										</figcaption>
									)}
								</>
							) : (
								<div className="motion-scroll-placeholder">
									<p>{__('Add images using the toolbar button', 'caes-motion-scroll')}</p>
								</div>
							)}
							{slides.length > 1 && (
								<div className="motion-scroll-image-count">
									+{slides.length - 1} {__('more', 'caes-motion-scroll')}
								</div>
							)}
						</div>
					</div>
					<div className="motion-scroll-editor-content" style={{
						...(isFeatherActive
							? { background: contentPosition === 'left'
									? `linear-gradient(to right, ${contentBackgroundColor} 65%, oklch(from ${contentBackgroundColor} l c h / 0) 100%)`
									: `linear-gradient(to right, oklch(from ${contentBackgroundColor} l c h / 0) 0%, ${contentBackgroundColor} 35%)` }
							: { backgroundColor: contentBackgroundColor || 'transparent' }
						),
						color: contentTextColor || 'inherit',
						paddingTop: getSpacingPresetCssVar(contentPadding?.top),
						paddingRight: getSpacingPresetCssVar(contentPadding?.right),
						paddingBottom: getSpacingPresetCssVar(contentPadding?.bottom),
						paddingLeft: getSpacingPresetCssVar(contentPadding?.left),
					}}>
						<InnerBlocks
							allowedBlocks={true}
							placeholder={__('Add content blocks here...', 'caes-motion-scroll')}
						/>
					</div>
				</div>
			</div>

			{/* Slide Manager Modal */}
			{showSlideManager && (
				<Modal
					title={__('Manage Images', 'caes-motion-scroll')}
					onRequestClose={() => setShowSlideManager(false)}
					className="motion-scroll-slide-manager-modal"
					style={{ maxWidth: '900px', width: '90vw' }}
				>
					<div style={{ padding: '20px 0' }}>
						<p style={{ marginBottom: '20px', color: '#757575' }}>
							{__('Add and configure images that will transition as the user scrolls through the content.', 'caes-motion-scroll')}
						</p>

						{slides.map((slide, index) => (
							<SlideManagerPanel
								key={slide.id || index}
								slide={slide}
								index={index}
								totalSlides={slides.length}
								onUpdate={(updates) => updateSlide(index, updates)}
								onRemove={() => removeSlide(index)}
								onMoveUp={() => moveSlideUp(index)}
								onMoveDown={() => moveSlideDown(index)}
								onDuplicate={() => duplicateSlide(index)}
								onSelectImage={(media) => onSelectImage(index, media)}
								onRemoveImage={() => onRemoveImage(index)}
								clientId={clientId}
							/>
						))}

						<Button variant="primary" onClick={addSlide} style={{ width: '100%', marginTop: '20px' }}>
							{__('Add Image', 'caes-motion-scroll')}
						</Button>

						<div style={{ marginTop: '20px', textAlign: 'right' }}>
							<Button variant="secondary" onClick={() => setShowSlideManager(false)}>
								{__('Done', 'caes-motion-scroll')}
							</Button>
						</div>
					</div>
				</Modal>
			)}
		</>
	);
};

// Slide Manager Panel Component
const SlideManagerPanel = ({
	slide,
	index,
	totalSlides,
	onUpdate,
	onRemove,
	onMoveUp,
	onMoveDown,
	onDuplicate,
	onSelectImage,
	onRemoveImage,
	clientId,
}) => {
	const [isOpen, setIsOpen] = useState(false);
	const [showFocalPointModal, setShowFocalPointModal] = useState(false);
	const [showDuotoneModal, setShowDuotoneModal] = useState(false);
	const [showMobileDuotoneModal, setShowMobileDuotoneModal] = useState(false);

	return (
		<div
			style={{
				border: '1px solid #ddd',
				borderRadius: '4px',
				marginBottom: '20px',
				background: '#fff',
			}}
		>
			{/* Header */}
			<div
				style={{
					display: 'flex',
					justifyContent: 'space-between',
					alignItems: 'center',
					padding: '16px',
					borderBottom: isOpen ? '1px solid #ddd' : 'none',
					background: '#f9f9f9',
					cursor: 'pointer',
				}}
				onClick={() => setIsOpen(!isOpen)}
			>
				<div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
					{/* Thumbnail */}
					{slide.image ? (
						<div
							style={{
								width: '60px',
								height: '40px',
								borderRadius: '4px',
								overflow: 'hidden',
								border: '1px solid #ddd',
								flexShrink: 0,
							}}
						>
							{(() => {
								const filterId = `thumbnail-${clientId}-${index}`;
								const duotone = slide.duotone;
								return (
									<>
										{Array.isArray(duotone) && duotone.length >= 2 && getDuotoneFilter(duotone, filterId)}
										<img
											src={slide.image.url}
											alt=""
											style={{
												width: '100%',
												height: '100%',
												objectFit: 'cover',
												filter: duotone ? `url(#${filterId})` : undefined,
											}}
										/>
									</>
								);
							})()}
						</div>
					) : (
						<div
							style={{
								width: '60px',
								height: '40px',
								borderRadius: '4px',
								border: '1px solid #ddd',
								background: '#e0e0e0',
								display: 'flex',
								alignItems: 'center',
								justifyContent: 'center',
								fontSize: '10px',
								color: '#666',
								flexShrink: 0,
							}}
						>
							No image
						</div>
					)}
					<strong style={{ fontSize: '16px' }}>
						{__('Image', 'caes-motion-scroll')} {index + 1}
					</strong>
				</div>
				<div style={{ display: 'flex', gap: '8px', alignItems: 'center' }} onClick={(e) => e.stopPropagation()}>
					{index > 0 && (
						<Button size="small" icon="arrow-up-alt2" onClick={onMoveUp} label={__('Move up', 'caes-motion-scroll')} />
					)}
					{index < totalSlides - 1 && (
						<Button size="small" icon="arrow-down-alt2" onClick={onMoveDown} label={__('Move down', 'caes-motion-scroll')} />
					)}
					<Button size="small" icon="admin-page" onClick={onDuplicate} label={__('Duplicate', 'caes-motion-scroll')} />
					{totalSlides > 1 && (
						<Button
							size="small"
							icon="trash"
							onClick={onRemove}
							label={__('Remove', 'caes-motion-scroll')}
							isDestructive
						/>
					)}
					<Button
						size="small"
						icon={isOpen ? 'arrow-up-alt2' : 'arrow-down-alt2'}
						onClick={(e) => {
							e.stopPropagation();
							setIsOpen(!isOpen);
						}}
						label={isOpen ? __('Collapse', 'caes-motion-scroll') : __('Expand', 'caes-motion-scroll')}
					/>
				</div>
			</div>

			{/* Content */}
			{isOpen && (
				<div style={{ padding: '20px' }}>
					<ImagePanel
						slide={slide}
						onSelectImage={onSelectImage}
						onRemoveImage={onRemoveImage}
						onUpdate={onUpdate}
						setShowFocalPointModal={setShowFocalPointModal}
						setShowDuotoneModal={setShowDuotoneModal}
						setShowMobileDuotoneModal={setShowMobileDuotoneModal}
						clientId={clientId}
						slideIndex={index}
					/>
				</div>
			)}

			{/* Modals */}
			{showFocalPointModal && (
				<FocalPointModal
					slide={slide}
					onUpdate={onUpdate}
					onClose={() => setShowFocalPointModal(false)}
				/>
			)}

			{showDuotoneModal && (
				<DuotoneModal
					slide={slide}
					onUpdate={onUpdate}
					onClose={() => setShowDuotoneModal(false)}
				/>
			)}

			{showMobileDuotoneModal && (
				<DuotoneModal
					slide={slide}
					onUpdate={onUpdate}
					onClose={() => setShowMobileDuotoneModal(false)}
					duotoneField="mobileDuotone"
				/>
			)}
		</div>
	);
};

// Image Panel Component
const ImagePanel = ({
	slide,
	onSelectImage,
	onRemoveImage,
	onUpdate,
	setShowFocalPointModal,
	setShowDuotoneModal,
	setShowMobileDuotoneModal,
	clientId,
	slideIndex,
}) => {
	const image = slide.image;
	const duotone = slide.duotone;

	return (
		<div>
			<label style={{ display: 'block', marginBottom: '8px', fontWeight: 500, fontSize: '13px', color: '#1e1e1e' }}>
				{__('Image', 'caes-motion-scroll')}
			</label>
			<p style={{ margin: '0 0 12px', fontSize: '12px', color: '#757575' }}>
				{__('Recommended: JPEG @ 1920 x 1080px. Set focus point for optimal display on desktop.', 'caes-motion-scroll')}
			</p>

			<MediaUploadCheck>
				{!image ? (
					<div>
						<MediaUpload
							onSelect={onSelectImage}
							allowedTypes={['image']}
							render={({ open }) => (
								<Button variant="secondary" onClick={open} style={{ width: '100%', height: '200px' }}>
									{__('Select Image', 'caes-motion-scroll')}
								</Button>
							)}
						/>
					</div>
				) : (
					<div>
						{/* Desktop Preview - simulates how the two-column layout looks */}
						<div style={{ marginBottom: '16px' }}>
							{(() => {
								const filterId = `manager-${clientId}-${slideIndex}`;
								const focalX = (slide.focalPoint?.x ?? 0.5) * 100;
								const focalY = (slide.focalPoint?.y ?? 0.5) * 100;

								const contentSide = (
									<div style={{
										flex: 1,
										background: '#f0f0f0',
										display: 'flex',
										flexDirection: 'column',
										justifyContent: 'center',
										padding: '12px',
										gap: '8px',
									}}>
										<div style={{ width: '60%', height: '6px', background: '#ccc', borderRadius: '3px' }} />
										<div style={{ width: '90%', height: '4px', background: '#ddd', borderRadius: '2px' }} />
										<div style={{ width: '80%', height: '4px', background: '#ddd', borderRadius: '2px' }} />
										<div style={{ width: '85%', height: '4px', background: '#ddd', borderRadius: '2px' }} />
										<div style={{ width: '40%', height: '4px', background: '#ddd', borderRadius: '2px', marginBottom: '6px' }} />
										<div style={{ width: '50%', height: '6px', background: '#ccc', borderRadius: '3px' }} />
										<div style={{ width: '95%', height: '4px', background: '#ddd', borderRadius: '2px' }} />
										<div style={{ width: '75%', height: '4px', background: '#ddd', borderRadius: '2px' }} />
										<div style={{ width: '88%', height: '4px', background: '#ddd', borderRadius: '2px' }} />
									</div>
								);

								const imageSide = (
									<div style={{
										flex: 1,
										position: 'relative',
										overflow: 'hidden',
										background: '#000',
									}}>
										<img
											src={image.url}
											alt={image.alt}
											style={{
												width: '100%',
												height: '100%',
												objectFit: 'cover',
												objectPosition: `${focalX}% ${focalY}%`,
												filter: duotone ? `url(#${filterId})` : undefined,
											}}
										/>
										{/* Focal point crosshair */}
										<div style={{
											position: 'absolute',
											left: `${focalX}%`,
											top: `${focalY}%`,
											transform: 'translate(-50%, -50%)',
											pointerEvents: 'none',
										}}>
											<div style={{
												width: '20px',
												height: '20px',
												borderRadius: '50%',
												border: '2px solid #fff',
												boxShadow: '0 0 0 1px rgba(0,0,0,0.4), inset 0 0 0 1px rgba(0,0,0,0.4)',
											}} />
											<div style={{ position: 'absolute', left: '50%', top: '-5px', width: '1px', height: '6px', background: '#fff', boxShadow: '0 0 1px rgba(0,0,0,0.5)', transform: 'translateX(-50%)' }} />
											<div style={{ position: 'absolute', left: '50%', bottom: '-5px', width: '1px', height: '6px', background: '#fff', boxShadow: '0 0 1px rgba(0,0,0,0.5)', transform: 'translateX(-50%)' }} />
											<div style={{ position: 'absolute', top: '50%', left: '-5px', width: '6px', height: '1px', background: '#fff', boxShadow: '0 0 1px rgba(0,0,0,0.5)', transform: 'translateY(-50%)' }} />
											<div style={{ position: 'absolute', top: '50%', right: '-5px', width: '6px', height: '1px', background: '#fff', boxShadow: '0 0 1px rgba(0,0,0,0.5)', transform: 'translateY(-50%)' }} />
										</div>
									</div>
								);

								return (
									<>
										{Array.isArray(duotone) && duotone.length >= 2 && getDuotoneFilter(duotone, filterId)}
										<div style={{ borderRadius: '4px', overflow: 'hidden', border: '1px solid #ddd' }}>
											<div style={{
												display: 'flex',
												aspectRatio: '16 / 9',
											}}>
												{contentSide}
												{imageSide}
											</div>
											<div style={{
												padding: '5px 8px',
												background: '#1e1e1e',
												color: '#bbb',
												fontSize: '11px',
												textAlign: 'center',
											}}>
												{__('Desktop preview — focus point applies in background mode', 'caes-motion-scroll')}
											</div>
										</div>
									</>
								);
							})()}
						</div>

						{/* Image Actions */}
						<div style={{ display: 'flex', gap: '8px', marginBottom: '16px' }}>
							<MediaUpload
								onSelect={onSelectImage}
								allowedTypes={['image']}
								value={image?.id}
								render={({ open }) => (
									<Button variant="secondary" onClick={open}>
										{__('Replace', 'caes-motion-scroll')}
									</Button>
								)}
							/>
							<Button variant="secondary" isDestructive onClick={onRemoveImage}>
								{__('Remove', 'caes-motion-scroll')}
							</Button>
						</div>

						{/* Alt Text */}
						<TextControl
							label={__('Alt Text', 'caes-motion-scroll') + ' (' + __('required', 'caes-motion-scroll') + ')'}
							value={image?.alt || ''}
							onChange={(value) => {
								const updatedImage = { ...image, alt: value };
								onUpdate({ image: updatedImage });
							}}
							placeholder={__('Describe image for screenreaders', 'caes-motion-scroll')}
						/>

						{/* Caption */}
						<TextControl
							label={__('Caption', 'caes-motion-scroll')}
							value={slide.caption || ''}
							onChange={(value) => onUpdate({ caption: value })}
							placeholder={__('Optional caption text', 'caes-motion-scroll')}
							help={__('Leave empty to hide caption', 'caes-motion-scroll')}
						/>

						{/* Focus & Filter Buttons */}
						<div style={{ display: 'flex', gap: '8px', marginTop: '16px', flexWrap: 'wrap', alignItems: 'center' }}>
							<Button variant="secondary" onClick={() => setShowFocalPointModal(true)} icon="image-crop">
								{__('Set Focus Point', 'caes-motion-scroll')}
							</Button>
							<Button variant="secondary" onClick={() => setShowDuotoneModal(true)} icon="admin-appearance">
								{duotone ? __('Edit Filter', 'caes-motion-scroll') : __('Add Filter', 'caes-motion-scroll')}
							</Button>
							{Array.isArray(duotone) && duotone.length >= 2 && <DuotoneSwatch values={duotone} />}
						</div>
					</div>
				)}
			</MediaUploadCheck>

			{/* Mobile Display Section */}
			<div style={{ marginTop: '24px', paddingTop: '20px', borderTop: '1px solid #e0e0e0' }}>
				<label style={{ display: 'block', marginBottom: '4px', fontWeight: 600, fontSize: '13px', color: '#1e1e1e' }}>
					{__('Mobile Display', 'caes-motion-scroll')}
				</label>
				<p style={{ margin: '0 0 12px', fontSize: '12px', color: '#757575' }}>
					{__('On mobile the full image is shown above content. If not set, the desktop image is used.', 'caes-motion-scroll')}
				</p>

				<MediaUploadCheck>
					{!slide.mobileImage ? (
						<div>
							<div style={{ padding: '10px 12px', background: '#f0f0f0', borderRadius: '4px', marginBottom: '12px', fontSize: '12px', color: '#555', fontStyle: 'italic' }}>
								{__('Using desktop image', 'caes-motion-scroll')}
							</div>
							<MediaUpload
								onSelect={(media) => onUpdate({
									mobileImage: {
										id: media.id,
										url: media.url,
										alt: media.alt || '',
										caption: media.caption || '',
										sizes: media.sizes || {},
										width: media.width || null,
										height: media.height || null,
									},
									mobileCaption: media.caption || '',
								})}
								allowedTypes={['image']}
								render={({ open }) => (
									<Button variant="secondary" onClick={open}>
										{__('Set Mobile Image', 'caes-motion-scroll')}
									</Button>
								)}
							/>
						</div>
					) : (
						<div>
							{/* Mobile image preview */}
							<div style={{ marginBottom: '16px' }}>
								{(() => {
									const mobileFilterId = `manager-mobile-${clientId}-${slideIndex}`;
									const mobileDuotone = slide.mobileDuotone;
									return (
										<>
											{mobileDuotone && getDuotoneFilter(mobileDuotone, mobileFilterId)}
											<div style={{ borderRadius: '4px', overflow: 'hidden', border: '1px solid #ddd' }}>
												<div style={{ position: 'relative', background: '#000', aspectRatio: '4 / 3', overflow: 'hidden' }}>
													<img
														src={slide.mobileImage.url}
														alt={slide.mobileImage.alt || ''}
														style={{
															width: '100%',
															height: '100%',
															objectFit: 'cover',
															objectPosition: 'center',
															filter: mobileDuotone ? `url(#${mobileFilterId})` : undefined,
														}}
													/>
												</div>
												<div style={{ padding: '5px 8px', background: '#1e1e1e', color: '#bbb', fontSize: '11px', textAlign: 'center' }}>
													{__('Mobile preview — full image, center-cropped', 'caes-motion-scroll')}
												</div>
											</div>
										</>
									);
								})()}
							</div>

							{/* Mobile Image Actions */}
							<div style={{ display: 'flex', gap: '8px', marginBottom: '16px' }}>
								<MediaUpload
									onSelect={(media) => onUpdate({
										mobileImage: {
											id: media.id,
											url: media.url,
											alt: media.alt || '',
											caption: media.caption || '',
											sizes: media.sizes || {},
											width: media.width || null,
											height: media.height || null,
										},
									})}
									allowedTypes={['image']}
									value={slide.mobileImage?.id}
									render={({ open }) => (
										<Button variant="secondary" onClick={open}>
											{__('Replace', 'caes-motion-scroll')}
										</Button>
									)}
								/>
								<Button
									variant="secondary"
									isDestructive
									onClick={() => onUpdate({ mobileImage: null, mobileCaption: '', mobileDuotone: null })}
								>
									{__('Remove', 'caes-motion-scroll')}
								</Button>
							</div>

							{/* Mobile Alt Text */}
							<TextControl
								label={__('Mobile Alt Text', 'caes-motion-scroll')}
								value={slide.mobileImage?.alt || ''}
								onChange={(value) => onUpdate({ mobileImage: { ...slide.mobileImage, alt: value } })}
								placeholder={__('Describe image for screenreaders', 'caes-motion-scroll')}
							/>

							{/* Mobile Caption */}
							<TextControl
								label={__('Mobile Caption', 'caes-motion-scroll')}
								value={slide.mobileCaption || ''}
								onChange={(value) => onUpdate({ mobileCaption: value })}
								placeholder={__('Optional mobile caption text', 'caes-motion-scroll')}
								help={__('Leave empty to hide caption', 'caes-motion-scroll')}
							/>

							{/* Mobile Filter Button */}
							<div style={{ display: 'flex', gap: '8px', marginTop: '16px', flexWrap: 'wrap', alignItems: 'center' }}>
								<Button variant="secondary" onClick={() => setShowMobileDuotoneModal(true)} icon="admin-appearance">
									{slide.mobileDuotone ? __('Edit Mobile Filter', 'caes-motion-scroll') : __('Add Mobile Filter', 'caes-motion-scroll')}
								</Button>
								{Array.isArray(slide.mobileDuotone) && slide.mobileDuotone.length >= 2 && <DuotoneSwatch values={slide.mobileDuotone} />}
							</div>
						</div>
					)}
				</MediaUploadCheck>
			</div>
		</div>
	);
};

// Focal Point Modal
const FocalPointModal = ({ slide, onUpdate, onClose }) => {
	const image = slide.image;
	const duotone = slide.duotone;
	const filterId = `focal-duotone-${slide.id || 'temp'}`;

	if (!image) {
		return null;
	}

	return (
		<Modal
			title={__('Set Focus Point', 'caes-motion-scroll')}
			onRequestClose={onClose}
			style={{ maxWidth: '600px', width: '100%' }}
		>
			<div style={{ padding: '8px 0' }}>
				<p style={{ margin: '0 0 16px 0', color: '#757575', fontSize: '13px' }}>
					{__('Click on the image to set the focal point. This determines which part of the image stays visible when cropped.', 'caes-motion-scroll')}
				</p>

				{Array.isArray(duotone) && duotone.length >= 2 && getDuotoneFilter(duotone, filterId)}
				{Array.isArray(duotone) && duotone.length >= 2 && (
					<style>{`.motion-scroll-focal-duotone .components-focal-point-picker img { filter: url(#${filterId}); }`}</style>
				)}
				<div className={Array.isArray(duotone) && duotone.length >= 2 ? 'motion-scroll-focal-duotone' : undefined}>
					<FocalPointPicker
						url={image.url}
						value={slide.focalPoint || { x: 0.5, y: 0.5 }}
						onChange={(value) => onUpdate({ focalPoint: value })}
					/>
				</div>

				<div style={{ marginTop: '20px', display: 'flex', justifyContent: 'flex-end' }}>
					<Button variant="primary" onClick={onClose}>
						{__('Done', 'caes-motion-scroll')}
					</Button>
				</div>
			</div>
		</Modal>
	);
};

// Duotone Modal
const DuotoneModal = ({ slide, onUpdate, onClose, duotoneField = 'duotone' }) => {
	const duotone = slide[duotoneField];

	return (
		<Modal
			title={duotoneField === 'mobileDuotone' ? __('Mobile Duotone Filter', 'caes-motion-scroll') : __('Duotone Filter', 'caes-motion-scroll')}
			onRequestClose={onClose}
			style={{ maxWidth: '400px', width: '100%' }}
		>
			<div style={{ padding: '8px 0' }}>
				<p style={{ margin: '0 0 16px 0', color: '#757575', fontSize: '13px' }}>
					{__('Apply a duotone color filter to this image. The first color replaces shadows, the second replaces highlights.', 'caes-motion-scroll')}
				</p>

				<DuotonePicker
					duotonePalette={DUOTONE_PALETTE}
					colorPalette={COLOR_PALETTE}
					value={Array.isArray(duotone) ? duotone : undefined}
					onChange={(value) => {
						// DuotonePicker may fire onChange with undefined/null when user clicks "Unset"
						const normalized = (Array.isArray(value) && value.length >= 2) ? value : null;
						onUpdate({ [duotoneField]: normalized });
					}}
				/>

				<div style={{ marginTop: '20px', display: 'flex', justifyContent: 'space-between' }}>
					{Array.isArray(duotone) && duotone.length >= 2 && (
						<Button
							variant="tertiary"
							isDestructive
							onClick={() => {
								onUpdate({ [duotoneField]: null });
								onClose();
							}}
						>
							{__('Remove Filter', 'caes-motion-scroll')}
						</Button>
					)}
					<div style={{ marginLeft: 'auto' }}>
						<Button variant="primary" onClick={onClose}>
							{__('Done', 'caes-motion-scroll')}
						</Button>
					</div>
				</div>
			</div>
		</Modal>
	);
};

export default Edit;
